import json
from dataclasses import dataclass, field
from pathlib import Path
from typing import Optional


@dataclass
class InsightCard:
    id: str
    summary: str
    frequency: int
    strength: str  # high | medium | low
    source_participant_ids: list[str]


@dataclass
class Requirement:
    id: str
    req_type: str   # user_story | nfr | anti_goal | acceptance_criterion
    text: str
    source_insight_id: str
    owner: str = ""
    sprint_target: Optional[int] = None
    linked_test_cases: list[str] = field(default_factory=list)


@dataclass
class TraceabilityMatrix:
    insights: dict[str, InsightCard]
    requirements: dict[str, Requirement]
    # insight_id -> [requirement_id]
    insight_to_requirements: dict[str, list[str]] = field(default_factory=dict)
    # requirement_id -> insight_id
    requirement_to_insight: dict[str, str] = field(default_factory=dict)

    def add_link(self, insight_id: str, requirement_id: str) -> None:
        if insight_id not in self.insights:
            raise ValueError(f"Unknown insight: {insight_id}")
        if requirement_id not in self.requirements:
            raise ValueError(f"Unknown requirement: {requirement_id}")
        self.insight_to_requirements.setdefault(insight_id, []).append(requirement_id)
        self.requirement_to_insight[requirement_id] = insight_id

    def orphaned_requirements(self) -> list[str]:
        # Requirements with no linked insight — indicates a traceability gap
        return [
            req_id for req_id in self.requirements
            if req_id not in self.requirement_to_insight
        ]

    def unactioned_insights(self) -> list[str]:
        # Insights that generated no requirements — may indicate synthesis gap
        return [
            ins_id for ins_id in self.insights
            if ins_id not in self.insight_to_requirements
        ]

    def coverage_report(self) -> dict:
        total_insights = len(self.insights)
        actioned = total_insights - len(self.unactioned_insights())
        total_reqs = len(self.requirements)
        traced = total_reqs - len(self.orphaned_requirements())
        return {
            "total_insights": total_insights,
            "actioned_insights": actioned,
            "insight_coverage_pct": round(actioned / total_insights * 100, 1) if total_insights else 0,
            "total_requirements": total_reqs,
            "traced_requirements": traced,
            "requirement_traceability_pct": round(traced / total_reqs * 100, 1) if total_reqs else 0,
            "orphaned_requirements": self.orphaned_requirements(),
            "unactioned_insights": self.unactioned_insights(),
        }

    def impact_of_removing_insight(self, insight_id: str) -> list[str]:
        # Which requirements would lose their research justification?
        return self.insight_to_requirements.get(insight_id, [])


def load_matrix_from_handoff_brief(brief_path: str) -> TraceabilityMatrix:
    with open(brief_path) as f:
        import yaml
        brief = yaml.safe_load(f)

    insights: dict[str, InsightCard] = {}
    requirements: dict[str, Requirement] = {}
    matrix = TraceabilityMatrix(insights=insights, requirements=requirements)

    for cap in brief.get("prioritised_capabilities", []):
        for ins_id in cap.get("insight_ids", []):
            if ins_id not in insights:
                insights[ins_id] = InsightCard(
                    id=ins_id, summary="", frequency=cap["participant_frequency"],
                    strength="high", source_participant_ids=[]
                )
        story_id = f"US-{cap['id'][-3:]}"
        requirements[story_id] = Requirement(
            id=story_id, req_type="user_story",
            text=cap["description"], source_insight_id=cap["insight_ids"][0],
            sprint_target=cap.get("sprint_target"), owner=cap.get("owner", "")
        )
        for ins_id in cap.get("insight_ids", []):
            matrix.add_link(ins_id, story_id)

    for nfr in brief.get("non_functional_requirements", []):
        req_id = nfr["id"]
        ins_id = nfr["source_insight"]
        if ins_id not in insights:
            insights[ins_id] = InsightCard(
                id=ins_id, summary="", frequency=0, strength="medium",
                source_participant_ids=[]
            )
        requirements[req_id] = Requirement(
            id=req_id, req_type="nfr", text=nfr["statement"],
            source_insight_id=ins_id, owner=nfr.get("owner", "")
        )
        matrix.add_link(ins_id, req_id)

    for ag in brief.get("anti_goals", []):
        req_id = ag["id"]
        ins_id = ag["source_insight"]
        if ins_id not in insights:
            insights[ins_id] = InsightCard(
                id=ins_id, summary="", frequency=0, strength="high",
                source_participant_ids=[]
            )
        requirements[req_id] = Requirement(
            id=req_id, req_type="anti_goal", text=ag["statement"],
            source_insight_id=ins_id
        )
        matrix.add_link(ins_id, req_id)

    return matrix


def print_coverage_report(matrix: TraceabilityMatrix) -> None:
    report = matrix.coverage_report()
    print("=== Traceability Coverage Report ===")
    print(f"Insights: {report['actioned_insights']}/{report['total_insights']} actioned "
          f"({report['insight_coverage_pct']}%)")
    print(f"Requirements: {report['traced_requirements']}/{report['total_requirements']} traced "
          f"({report['requirement_traceability_pct']}%)")
    if report["orphaned_requirements"]:
        print(f"WARNING: {len(report['orphaned_requirements'])} orphaned requirements:")
        for req_id in report["orphaned_requirements"]:
            print(f"  - {req_id}")
    if report["unactioned_insights"]:
        print(f"WARNING: {len(report['unactioned_insights'])} unactioned insights:")
        for ins_id in report["unactioned_insights"]:
            print(f"  - {ins_id}")
    if report["requirement_traceability_pct"] == 100.0 and report["insight_coverage_pct"] == 100.0:
        print("OK: Full traceability achieved.")
